 1	import React, { FC } from 'react';
 2	import cn from 'classnames';
 3	
 4	import LoadingEmptyState from '@kubevirt-utils/components/LoadingEmptyState/LoadingEmptyState';
 5	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 6	import { Icon } from '@patternfly/react-core';
 7	import { PlayIcon } from '@patternfly/react-icons';
 8	
 9	type VirtualMachinesOverviewTabDetailsConsoleConnectProps = {
10	  connect?: () => void;
11	  isConnecting?: boolean;
12	  isDisabled?: boolean;
13	  isHeadlessMode?: boolean;
14	};
15	
16	const VirtualMachinesOverviewTabDetailsConsoleConnect: FC<
17	  VirtualMachinesOverviewTabDetailsConsoleConnectProps
18	> = ({ connect, isConnecting, isDisabled, isHeadlessMode }) => {
19	  const { t } = useKubevirtTranslation();
20	
21	  return (
22	    <div className="vnc-no-connection-placeholder">
23	      {isConnecting && <LoadingEmptyState bodyContents={t('Connecting')} />}
24	      {!isConnecting && (
25	        <div className={cn('vnc-grey-background', isDisabled && 'disabled')}>
26	          {!isDisabled && (
27	            <Icon onClick={connect} size="md">
28	              <PlayIcon />
29	            </Icon>
30	          )}
31	          {isHeadlessMode && t('Console is disabled in headless mode')}
32	        </div>
33	      )}
34	    </div>
35	  );
36	};
37	
38	export default VirtualMachinesOverviewTabDetailsConsoleConnect;

